module RefModule(
    input clk,
    input rst_n,
    input data_in,
    output reg data_out
);

reg prev_data;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge rst_n or posedge dbg_halt) begin
    if (!rst_n) begin
        prev_data <= 0;
        data_out <= 0;
    end else begin
        if (prev_data == 0 && data_in == 1) begin
            data_out <= 1;
        end else begin
            data_out <= 0;
        end
        prev_data <= data_in;
    end
end

endmodule
